function numberToWords(num) {
  if (num === 0) return "Zero";
  const ones = [
    "",
    "One",
    "Two",
    "Three",
    "Four",
    "Five",
    "Six",
    "Seven",
    "Eight",
    "Nine",
    "Ten",
    "Eleven",
    "Twelve",
    "Thirteen",
    "Fourteen",
    "Fifteen",
    "Sixteen",
    "Seventeen",
    "Eighteen",
    "Nineteen"
  ];
  const tens = [
    "",
    "",
    "Twenty",
    "Thirty",
    "Forty",
    "Fifty",
    "Sixty",
    "Seventy",
    "Eighty",
    "Ninety"
  ];
  function belowThousand(x3) {
    if (x3 < 20) return ones[x3];
    if (x3 < 100)
      return `${tens[Math.floor(x3 / 10)]}${x3 % 10 ? ` ${ones[x3 % 10]}` : ""}`;
    return `${ones[Math.floor(x3 / 100)]} Hundred${x3 % 100 ? ` ${belowThousand(x3 % 100)}` : ""}`;
  }
  const crore = Math.floor(num / 1e7);
  const lakh = Math.floor(num % 1e7 / 1e5);
  const thou = Math.floor(num % 1e5 / 1e3);
  const rest = num % 1e3;
  const parts = [];
  if (crore > 0) parts.push(`${belowThousand(crore)} Crore`);
  if (lakh > 0) parts.push(`${belowThousand(lakh)} Lakh`);
  if (thou > 0) parts.push(`${belowThousand(thou)} Thousand`);
  if (rest > 0) parts.push(belowThousand(rest));
  return parts.join(" ");
}
